//------------------------------------------------------------------------------

assign etherbone_clk = sys_clk;
assign etherbone_rst = sys_rst;
assign arp_rx_fire = (de2_115vgamaster_ethcore_arp_rx_source_source_valid & de2_115vgamaster_ethcore_arp_rx_source_source_ready);
assign arp_tx_sink_fire = (de2_115vgamaster_ethcore_arp_tx_sink_sink_valid & de2_115vgamaster_ethcore_arp_tx_sink_sink_ready);
assign arp_tx_source_fire = (de2_115vgamaster_ethcore_arp_tx_source_source_valid & de2_115vgamaster_ethcore_arp_tx_source_source_ready);
assign vga_sync_n = 1'd0;
assign sys_rst_debug = sys_rst;
assign force_hpi_boot = 1'd0;
always @(*) begin
    de2_115vgamaster_interrupt <= 32'd0;
    de2_115vgamaster_interrupt[0] <= de2_115vgamaster_ethcore_mac_wishbone_interface_ev_irq;
    de2_115vgamaster_interrupt[3] <= de2_115vgamaster_ev_irq;
    de2_115vgamaster_interrupt[1] <= de2_115vgamaster_timer_irq;
    de2_115vgamaster_interrupt[2] <= de2_115vgamaster_uart_irq;
end
assign de2_115vgamaster_converter0_done = (de2_115vgamaster_converter0_count == 2'd3);
